namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<Notification> GetNotificationsSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally by the service to generate fake data.
    /// </summary>
    public void SimulateIncoming()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready to download.",
            "A comment was added to your thread.",
            "Weekly summary is available.",
        };

        lock (_lock)
        {
            var msg = messages[(_nextId - 1) % messages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

@page "/notifications"
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable
@rendermode @(new InteractiveServerRenderMode(prerender: true))

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;
    private bool _isInteractive;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // This ensures SSR HTML contains the data immediately.
        notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender && !_isInteractive)
        {
            // OnAfterRender only fires in interactive mode (not during static SSR).
            // This is the signal that the component is now live in the browser.
            _isInteractive = true;
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        // Track the highest ID we already have to fetch only new ones
        var lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                // Simulate a new notification arriving server-side
                NotificationService.SimulateIncoming();

                var newItems = NotificationService.GetNotificationsSince(lastSeenId);
                if (newItems.Count > 0)
                {
                    notifications.AddRange(newItems);
                    lastSeenId = newItems.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                // Expected on dispose — exit gracefully
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

